(102, 'w9', '', 'Women\'s Blue Textured Co-ord Set', 'A stylish and comfortable co-ord set featuring a textured t-shirt and matching relaxed-fit pants. Perfect for casual outings or lounging.', 'The set is made from a soft, breathable fabric with a subtle diagonal texture. The t-shirt has a classic crew neck and short sleeves. The pants feature a comfortable elastic waistband and a relaxed, tapered leg with a small slit at the hem. Side pockets are included on the pants.', 'pictures/products/1781777577_6a33c4a9e0f3d_w9.jpg', '', '', 'XS:0, S:0, L:0, XL:50', 1299.00, '', NULL, 57, 0, 20, '0', 'Shop this comfortable and chic women\'s blue textured co-ord set. Features a stylish t-shirt and relaxed-fit pants, ideal for everyday wear.', 'co-ord set, women\'s set, t-shirt and pants, blue outfit, textured fabric, casual wear, loungewear', '2026-06-18 10:12:57', '2026-06-18 10:12:57', 'women-s-blue-textured-co-ord-set', 'Yes', 50, 0),
(103, 'w10', '', 'Women\'s Classic Fit White Cotton Full Sleeve Shirt', 'A timeless and versatile white cotton shirt for women, perfect for both formal and casual wear. Featuring a classic fit and full sleeves, this shirt offers comfort and style.', 'Crafted from 100% premium cotton, this shirt ensures breathability and a soft feel against the skin. It features a pointed collar, a button-down front closure, and buttoned cuffs for adjustable fit. The tailored seams provide a flattering silhouette.', 'pictures/products/1781777910_6a33c5f69d632_w10.jpg', '', '', 'XS:50, S:0, L:0, XL:0', 1500.00, '', NULL, 57, 0, 20, '0', 'Shop for a stylish and comfortable women\'s white cotton full sleeve shirt. Perfect for office wear and everyday style. Get it at a competitive price with fast delivery.', 'women shirt, white shirt, cotton shirt, full sleeve shirt, formal shirt, casual shirt, office wear, ladies shirt, ladies fashion', '2026-06-18 10:18:30', '2026-06-18 10:18:30', 'women-s-classic-fit-white-cotton-full-sleeve-shirt', 'Yes', 50, 0),
(104, 'w8', '', 'Women\'s Brown Oversized Cotton Shirt', 'A chic and comfortable oversized shirt in a warm brown hue. Perfect for a casual yet stylish look.', 'Made from breathable cotton fabric. Features a classic collar, button-down front, and a single chest pocket. The oversized fit provides a relaxed and contemporary silhouette.', 'pictures/products/1781778077_6a33c69d5c9c3_w8.webp', '', '', 'XS:0, S:0, L:50, XL:0', 1599.00, '', NULL, 57, 0, 0, '0', 'Shop the latest collection of women\'s oversized cotton shirts. This stylish brown shirt is perfect for everyday wear. Available in various sizes. Free shipping on orders above Rs. [Amount].', 'brown shirt, oversized shirt, women\'s shirt, cotton shirt, casual wear, fashion shirt, button-down shirt, stylish shirt, comfortable shirt', '2026-06-18 10:21:17', '2026-06-18 12:01:22', 'women-s-brown-oversized-cotton-shirt', 'Yes', 50, 0),
(105, 'w4', '', 'Women\'s Striped Short Sleeve Shirt', 'A stylish and comfortable short-sleeved shirt featuring subtle vertical stripes. Perfect for casual outings or a relaxed day at home.', 'Crafted from a breathable cotton blend fabric, this shirt offers a relaxed fit with a classic collar and button-down front. The short sleeves are finished with a neat cuff detail.', 'pictures/products/1781778173_6a33c6fd3d488_w4.jpg', '', '', 'XS:0, S:0, L:50, XL:0', 1399.00, '', NULL, 57, 0, 20, '0', 'Shop for our trendy women\'s striped short sleeve shirt. Made with a soft cotton blend, it\'s perfect for everyday wear. Available in various sizes.', 'women\'s shirt, striped shirt, short sleeve shirt, casual shirt, cotton blend, women\'s fashion, online shopping', '2026-06-18 10:22:53', '2026-06-18 10:22:53', 'women-s-striped-short-sleeve-shirt', 'Yes', 50, 0),
(106, 'w3', '', 'Women\'s Burgundy Collared Puff Sleeve Button-Up Shirt', 'A stylish and elegant burgundy shirt for women, featuring a classic collared neckline, puff sleeves for a touch of volume, and a flattering button-up front. This versatile shirt can be dressed up or down for various occasions.', 'Made from a blend of cotton and polyester, this shirt offers comfort and durability. The fabric is breathable and easy to care for. It features a pointed collar, short puff sleeves, and a concealed button placket with decorative buttons visible on the outside. The design includes subtle pleating at the waist for a tailored fit.', 'pictures/products/1781778302_6a33c77ec720f_w3.jpg', '', '', 'XS:0, S:0, L:50, XL:0', 1350.00, '', NULL, 57, 0, 20, '0', 'Shop for a chic burgundy collared shirt with puff sleeves. Perfect for office wear or casual outings, this button-up top offers a blend of style and comfort.', 'burgundy shirt, women\'s shirt, collared shirt, puff sleeve shirt, button-up shirt, formal shirt, casual shirt, fashion top', '2026-06-18 10:25:02', '2026-06-18 10:25:02', 'women-s-burgundy-collared-puff-sleeve-button-up-shirt', 'Yes', 50, 0),
(107, 'w2', '', 'Lavender Puff Sleeve Peplum Top', 'A stylish lavender top with elegant puff sleeves and a flattering peplum silhouette. Features a classic collar and button-down front.', 'Fabric: Cotton blend. Style: Peplum, collared, button-down, short puff sleeves.', 'pictures/products/1781778386_6a33c7d2ccf06_w2.webp', '', '', 'XS:0, S:0, L:50, XL:0', 1099.00, '', NULL, 57, 0, 20, '0', 'Shop for a chic lavender puff sleeve peplum top. Perfect for casual and semi-formal occasions. Available online at an affordable price.', 'peplum top, puff sleeve top, lavender top, women\'s top, casual wear, formal wear, stylish top', '2026-06-18 10:26:26', '2026-06-23 12:53:07', 'lavender-puff-sleeve-peplum-top', 'Yes', 49, 0),
(108, 'w1', '', 'Women\'s White Puff Sleeve Collared Shirt', 'A chic and versatile white shirt with subtle puff sleeves and a classic collar, perfect for both casual and formal occasions.', 'Crafted from a comfortable cotton blend, this shirt features a tailored fit, a V-neckline with a notch collar, button-down front with golden buttons, and elegant puff sleeves with a cuffed hem. The fabric offers a soft feel and good breathability.', 'pictures/products/1781778532_6a33c8640da55_w1.webp', '', '', 'XS:0, S:0, L:50, XL:0', 1399.00, '', NULL, 57, 0, 20, '0', 'Shop for the latest collection of women\'s white puff sleeve collared shirts. Comfortable, stylish, and perfect for any occasion. Get the best prices online.', 'white shirt, puff sleeve shirt, collared shirt, women\'s shirt, formal shirt, casual shirt, cotton blend shirt', '2026-06-18 10:28:52', '2026-06-18 10:28:52', 'women-s-white-puff-sleeve-collared-shirt', 'Yes', 50, 0),
(109, 'w11', '', 'Black Hoodie and Jogger Set with Red Accents', 'A comfortable and stylish black hoodie and jogger set for women, featuring subtle red brand logo detailing and contrasting red stripes on the cuffs and hood lining.', 'Crafted from a soft and breathable cotton blend fabric for all-day comfort. The hoodie has a classic pullover design with an adjustable drawstring hood and a kangaroo pocket. The joggers feature a comfortable elastic waistband with a drawstring, side pockets, and ribbed cuffs. The brand\'s signature red logo is embroidered on the chest of the hoodie and the thigh of the joggers. Red stripe details accent the cuffs of the hoodie sleeves and the waistband of the joggers.', 'pictures/products/1781779425_6a33cbe11d5f6_DSC_5266-min_1000x.jpg', '', '', 'XS:0, S:0, L:0, XL:50', 1999.00, '', NULL, 57, 0, 20, '0', 'Shop the latest Women\'s Black Hoodie and Jogger Set featuring stylish red accents and brand logo. Perfect for casual wear and athleisure. Made with comfortable cotton blend.', 'women\'s tracksuit, hoodie and joggers set, black athleisure, red accent clothing, comfortable loungewear, fashion set, casual wear, cotton blend tracksuit', '2026-06-18 10:43:45', '2026-06-18 10:43:45', 'black-hoodie-and-jogger-set-with-red-accents', 'Yes', 50, 0),
(110, 'w12', '', 'Women\'s Red Crew Neck T-Shirt', 'A vibrant red crew neck t-shirt designed for everyday comfort and style. This t-shirt features a subtle embroidered logo on the chest, adding a touch of brand identity.', 'Crafted from a soft and breathable cotton blend fabric, this t-shirt offers a relaxed fit. It has short sleeves and a classic crew neckline, making it a versatile piece for casual wear.', 'pictures/products/1781779575_6a33cc7777f58_171A2102copy_94b2151a-25fc-40bf-bbe0-0a1921e8cec4_1000x.webp', '', '', 'XS:0, S:0, L:0, XL:50', 599.00, '', NULL, 57, 0, 20, '0', 'Shop the latest collection of women\'s red crew neck t-shirts made from comfortable cotton blend. Perfect for daily wear, casual outings, and layering. Affordable prices and fast delivery.', 'red t-shirt, women\'s t-shirt, cotton t-shirt, crew neck t-shirt, casual wear, everyday wear, basic t-shirt, women\'s apparel, embroidered t-shirt', '2026-06-18 10:46:15', '2026-06-18 10:46:15', 'women-s-red-crew-neck-t-shirt', 'Yes', 50, 0),
